 1	import {
 2	  MenuToggle,
 3	  MenuToggleElement,
 4	  Select,
 5	  SelectList,
 6	  SelectOption,
 7	} from '@patternfly/react-core';
 8	import React from 'react';
 9	import { useTranslation } from 'react-i18next';
10	import { Schema } from '../logs.types';
11	import { TestIds } from '../test-ids';
12	
13	type SchemaDropdownProps = {
14	  onSchemaSelected: ((schema: Schema) => void) | undefined;
15	  schema: Schema;
16	};
17	
18	export const SchemaDropdown: React.FC<SchemaDropdownProps> = ({ onSchemaSelected, schema }) => {
19	  const { t } = useTranslation('plugin__logging-view-plugin');
20	
21	  const [isOpen, setIsOpen] = React.useState(false);
22	
23	  const schemaSelectRef = React.useRef<HTMLDivElement>(null);
24	
25	  const onToggle = () => setIsOpen(!isOpen);
26	  const onSelect = (
27	    _: React.MouseEvent<Element, MouseEvent> | undefined,
28	    value: string | number | undefined,
29	  ) => {
30	    if (value != schema) {
31	      onSchemaSelected?.(value as Schema);
32	    }
33	    setIsOpen(false);
34	  };
35	
36	  const handleClickOutside = (event: MouseEvent) => {
37	    if (isOpen && !schemaSelectRef.current?.contains(event.target as Node)) {
38	      setIsOpen(false);
39	    }
40	  };
41	
42	  React.useEffect(() => {
43	    if (isOpen) {
44	      window.addEventListener('click', handleClickOutside);
45	    }
46	    return () => {
47	      window.removeEventListener('click', handleClickOutside);
48	    };
49	  }, [isOpen]);
50	
51	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
52	    <MenuToggle
53	      ref={toggleRef}
54	      onClick={onToggle}
55	      isExpanded={isOpen}
56	      data-test={TestIds.SchemaToggle}
57	    >
58	      {schema}
59	    </MenuToggle>
60	  );
61	
62	  return (
63	    <div ref={schemaSelectRef}>
64	      <Select
65	        id="logging-view-schema-dropdown"
66	        isOpen={isOpen}
67	        onSelect={onSelect}
68	        placeholder={t('Select a Schema')}
69	        toggle={toggle}
70	      >
71	        <SelectList>
72	          <SelectOption key={'otel'} value={Schema.otel} isSelected={schema === Schema.otel}>
73	            otel
74	          </SelectOption>
75	          <SelectOption key={'viaq'} value={Schema.viaq} isSelected={schema === Schema.viaq}>
76	            viaq
77	          </SelectOption>
78	        </SelectList>
79	      </Select>
80	    </div>
81	  );
82	};

